('Throwing Athlete Shoulder Program (ASMI)',
 'rotator_cuff', array['shoulder','core','hip_flexors'], array['rotator_cuff','shoulder','core'],
 'rehab', 'strength', array['resistance_bands','dumbbells'], 'intermediate', false,
 'American Sports Medicine Institute (ASMI) interval throwing program adapted for fitness coaching. Foundation: (1) Scapular strengthening: Y-T-W, serratus activation 3x/week. (2) Rotator cuff: all four muscles 3x/week. (3) Core: anti-rotation, pallof press for throwing stability. (4) Hip and lower extremity: single-leg stability for throwing base. Throwing progression: distance-based starting at 10m progressing to full distance over 6-12 weeks.',
 'Throwing at full intensity without the strengthening base; increasing throwing distance too fast; not including lower extremity in shoulder program; ignoring the opposite rotator cuff.',
 'shoulder_rehab', array['Throwing starts from the ground: hip and leg produce the power','Both shoulders: the non-throwing shoulder matters for balanced loading','Rotator cuff is the brake: it decelerates every throw — train it','Interval throwing: progress distance before velocity'],
 array['Full return to competition throwing','Velocity building after distance established','Pitching mechanics assessment and correction'],
 array['Rotator cuff basic strengthening only','No-throw phase while building base','Catch and light toss only'],
 array['shoulder','throwing_athlete','baseball','cricket','ASMI','rotator_cuff','return_to_throw'], array['active_impingement','instability_unaddressed'],
 'mixed', 'multi', true, 3, null, null, 45, true),

('AC Joint Sprain Rehabilitation',
 'shoulder', array['traps','rotator_cuff','deltoid'], array['shoulder','traps','rotator_cuff'],
 'rehab', 'strength', array['resistance_bands','dumbbells'], 'beginner', false,
 'Acromioclavicular joint (collarbone-shoulder) sprain. Grade 1-2 conservative protocol: (1) Week 1-2: sling, ice, gentle pendulum. (2) Week 3-4: active ROM, scapular stabilization. (3) Week 5-8: rotator cuff strengthening, progressive loading. (4) Week 8-12: sport-specific return. Avoid: horizontal adduction exercises (cross-body movements stress the AC joint) for 8-10 weeks. Grade 3+: surgical consult required.',
 'Cross-body movements too early (AC joint stress); returning to contact sport before 10-12 weeks (Grade 2); bench press loading too early (significant AC joint load); not managing the superior step deformity long-term.',
 'shoulder_rehab', array['AC joint: the bump deformity — cosmetic after Grade 2','Avoid cross-body: horizontal adduction stresses the AC joint','Bench press: heavy loading avoided 8-10 weeks minimum','Return to contact: only when full ROM and strength achieved'],
 array['Full overhead sport return','Contact sport return with AC joint protection','Heavy bench press return program'],
 array['Sling support and pendulum only','Ice and activity modification','Gentle ROM within pain'],
 array['AC_joint','acromioclavicular','sprain','rehabilitation','shoulder'], array['Grade_3_4_AC_requiring_surgery'],
 'mixed', 'multi', true, 3, null, null, 45, true);


