('Tibialis Posterior Tendinopathy',
 'tibialis_posterior', array['calves','foot_arch','peroneals'], array['tibialis_posterior','calves'],
 'rehab', 'strength', array['resistance_bands','step'], 'intermediate', false,
 'Tibialis posterior tendinopathy is the primary cause of adult-acquired flat foot. Progressive loading program: (1) Isometric: single-leg calf raise on a turned-in position (tibialis posterior emphasis) 3x45s hold. (2) Eccentric: single-leg heel drop with foot inverted (supinated) 3x15. (3) Resistance band inversion 3x20 each foot. (4) Arch strengthening: short foot exercise 3x15. (5) Activity modification: avoid barefoot/flats temporarily. Orthotic support during healing phase.',
 'Treating like standard calf/Achilles (different muscle, different protocol); not addressing overpronation; continuing barefoot on hard floors; not using orthotic support during loading phase.',
 'ankle_rehab', array['Tibialis posterior: the arch''s primary dynamic support','Inverted position: turns the foot inward for tibialis posterior bias','Short foot: building arch intrinsic strength prevents recurrence','Orthotics: support while you rebuild strength, then wean off'],
 array['Return to running with arch support','Sports return with tibialis posterior strength test','Tibialis posterior strengthening maintenance program'],
 array['Orthotics and rest only','Non-weight bearing brief period','Gentle stretching and activity modification'],
 array['tibialis_posterior','tendinopathy','flat_foot','arch','ankle','rehabilitation'], array['tibialis_posterior_tendon_rupture'],
 'mixed', 'sagittal', true, 3, 15, null, 45, true),

('Hallux Valgus (Bunion) Conservative Management',
 'foot_intrinsics', array['tibialis_posterior','peroneals','calves'], array['foot_intrinsics','tibialis_posterior'],
 'rehab', 'strength', array['toe_separators','resistance_bands'], 'beginner', false,
 'Conservative management for bunion (hallux valgus deformity). (1) Intrinsic foot strengthening: toe spreads 3x20, short foot exercise 3x15. (2) First ray mobility: big toe extension mobilization 3x15. (3) Hip strengthening: reducing valgus collapse that drives foot pronation. (4) Footwear: wide toe box shoes — avoid narrow pointed shoes. (5) Toe separators during rest and exercise. (6) Activity modification: avoid prolonged standing in narrow shoes.',
 'Tight narrow footwear (primary driver of bunion progression); ignoring intrinsic foot weakness; not addressing hip weakness and overpronation upstream cause; expecting reversal of bony deformity (conservative cannot reverse, only slow progression).',
 'foot_rehab', array['Wide shoes: the bunion cannot be reversed but can be slowed','Intrinsic strength: the small muscles maintain big toe alignment','Hip strength reduces pronation which reduces bunion stress','Conservative: prevents progression — surgery is the only reversal'],
 array['Custom orthotics fitting','Full foot and hip assessment','Bunion surgery when conservative fails'],
 array['Toe separator use only','Footwear change with monitoring','Bunion night splint gentle correction'],
 array['hallux_valgus','bunion','foot','intrinsic_strength','conservative','rehabilitation'], array['severe_osteoarthritis_first_MTP'],
 'mixed', 'multi', true, 3, 20, null, 20, true),

('Stress Fracture Return-to-Running Protocol',
 'cardiovascular', array['quads','calves','glutes'], array['cardiovascular','quads','calves'],
 'rehab', 'running', array['running_shoes','bike','pool'], 'intermediate', false,
 'Evidence-based return to running after bone stress injury (tibial, metatarsal, femoral). Phase 1: Aqua jogging/pool running 20-30 min 3x/week for pain-free period. Phase 2: Walking 20 minutes pain-free 5x/week x2 weeks. Phase 3: Walk/jog alternate (jog 1 min / walk 4 min x5) x2 weeks. Phase 4: Continuous 10-minute jog. Build: +10% per week. Return criteria: imaging confirming healing + pain-free walking.',
 'Running before imaging confirms healing; too fast volume increase; returning to running on hard surfaces before soft; not addressing the causative factors (training load, nutrition, footwear).',
 'bone_stress_rehab', array['Imaging confirmation: you cannot feel healing — imaging confirms it','Pool running maintains fitness without bone impact','10% rule: never increase running load >10% per week','Address the cause: sudden load increase, calcium deficit, menstrual dysfunction'],
 array['Full training volume return','Trail running on soft surface','Return to sport specific training'],
 array['Pool running only until healed','Cycling for non-impact cardio','Complete rest from impact for first 4-6 weeks'],
 array['stress_fracture','bone_stress_injury','running_return','rehabilitation','bone_healing'], array['confirmed_stress_fracture_before_healing_imaging'],
 'mixed', 'sagittal', false, 1, null, null, null, true);

